#include <stdio.h>
#include <string.h>

int main() {
    int T; 
    if (scanf("%d", &T) != 1) return 0;
    const char pattern[4] = "abc"; // null‑terminated
    while (T--) {
        int N; scanf("%d", &N);
        char *s = (char*)malloc(N + 1);
        for (int i = 0; i < N; ++i) s[i] = pattern[i % 3];
        s[N] = '\0';
        printf("%s\n", s);
        free(s);
    }
    return 0;
}

